async syncPackageList({commit, dispatch, state, rootGetters}): Promise<void> {
            if (state.isThunderstoreModListUpdateInProgress || rootGetters['download/activeDownloadCount'] > 0) {
                return;
            }

            commit('startThunderstoreModListUpdate');

            try {
                commit('setThunderstoreModListUpdateStatus', 'Checking for mod list updates from Thunderstore...');
                const packageListIndex = await dispatch('fetchPackageListIndex');

                // If the package list is up to date, only update the timestamp. Otherwise,
                // fetch the new one and store it into IndexedDB.
                if (packageListIndex.isLatest) {
                    await dispatch('cacheIndexHash', packageListIndex.hash);
                } else {
                    const areAllChunksProcessedSuccessfully = await dispatch(
                        'fetchAndCachePackageListChunks',
                        {
                            packageListIndex,
                            progressCallback: (progress: number) => commit(
                                'setThunderstoreModListUpdateStatus',
                                `Loading latest mod list from Thunderstore: ${progress}%`
                            ),
                        },
                    );

                    if (areAllChunksProcessedSuccessfully) {
                        commit('setThunderstoreModListUpdateStatus', 'Pruning removed mods from local cache...');
                        await dispatch('pruneRemovedModsFromCache', packageListIndex.dateFetched);
                    }
                }

                // If the package list was up to date and the mod list is already loaded to
                // Vuex, just update the timestamp. Otherwise, load the list from IndexedDB
                // to Vuex. This needs to be done even if the index hasn't updated when the
                // mod list in Vuex is empty, as this indicates an error state and otherwise
                // the user would be stuck with empty list until a new index hash is
                // available via the API.
                if (packageListIndex.isLatest && state.mods.length > 0) {
                    await dispatch('updateModsLastUpdated');
                } else {
                    commit('setThunderstoreModListUpdateStatus', 'Processing the mod list...');
                    await dispatch('updateMods');
                    commit('setThunderstoreModListUpdateStatus', 'Almost done...');
                    await dispatch('profile/tryLoadModListFromDisk', null, {root: true});
                    await dispatch('prewarmCache');
                }
            } catch (e) {
                commit('setThunderstoreModListUpdateError', e);
            } finally {
                commit('setActiveGameCacheStatus', undefined);
                commit('finishThunderstoreModListUpdate');
            }
        }

splitToNameAndVersion = (dependencyString: string): [string, string] => {
    const parts = dependencyString.split('-');

    // Legacy team names can contain hyphens, so we can't be sure how
    // many there are in a dependency string.
    if (parts.length < 3) {
        throw new Error(`Invalid dependency string "${dependencyString}"`);
    }

    const version = parts.pop()!;
    const fullName = parts.join('-');
    return [fullName, version];
}

async function getFullDependencyList(
    combos: ThunderstoreCombo[],
    game: Game,
    installedMods: ManifestV2[],
    installMode: InstallMode
): Promise<ThunderstoreCombo[]> {
    const results = [...combos];

    for (const combo of combos) {
        const isModpack = combo.getMod().getCategories().some(value => value === "Modpacks");
        const dependencyVersionStrategy = installMode === InstallMode.INSTALL_SPECIFIC && isModpack
            ? ModpackDependencyStrategy.USE_EXACT_VERSION
            : ModpackDependencyStrategy.USE_LATEST_VERSION;

        let dependencies: ThunderstoreCombo[] = [];
        await buildDependencySet(combo.getVersion(), game, dependencies, dependencyVersionStrategy);

        if (installMode === InstallMode.INSTALL_SPECIFIC && !isModpack) {
            dependencies = dependencies.filter(
                (dependency) => !installedMods.some(installed => installed.getName() === dependency.getMod().getFullName())
            );
        }

        results.push(...dependencies.filter(
            (dependency) => !results.some(alreadyAdded => alreadyAdded.getMod().getFullName() === dependency.getMod().getFullName())
        ));
    }

    sortDependencyOrder(results);
    return results;
}

makeLongRunningGetRequest = async (
    url: string,
    options: Partial<LongRunningRequestOptions> = {}
) => {
    const {
        axiosConfig = {},
        downloadProgressed = () => null,
        initialTimeout = 30 * 1000,
        totalTimeout = 5 * 60 * 1000,
        transmissionTimeout = 60 * 1000
    } = options;

    const abortController = new AbortController();
    const abort = () => abortController.abort();  // Set valid this.
    const sanityTimeout = setTimeout(abort, totalTimeout);
    let rollingTimeout = setTimeout(abort, initialTimeout);

    const onDownloadProgress = (progress: ProgressEvent) => {
        clearTimeout(rollingTimeout);
        rollingTimeout = setTimeout(abort, transmissionTimeout);

        if (typeof downloadProgressed === "function") {
            // Backend might not provided total content length.
            const percent = progress.total ? (progress.loaded / progress.total) * 100 : 0;
            downloadProgressed(percent);
        }
    }

    const instance = axios.create({
        ...axiosConfig,
        onDownloadProgress,
        signal: abortController.signal,
    });

    try {
        return await instance.get(url);
    } finally {
        clearTimeout(sanityTimeout);
        clearTimeout(rollingTimeout);
    }
}

