function formatOutgoingCharacteristicValue(value: Nullable<CharacteristicValue>, props: CharacteristicProps): Nullable<CharacteristicValue> {
  if (typeof value === "boolean") {
    return value? 1: 0;
  } else if (typeof value === "number") {
    if (!props.minStep || props.minStep >= 1) {
      return value;
    }

    const base = props.minValue ?? 0;
    const inverse = 1 / props.minStep;

    return Math.round(((Math.round((value - base) * inverse) / inverse) + base) * 10000) / 10000;
  }

  return value;
}

