deepClone = <T>(obj: T): T => {
  if (isArray(obj)) {
    return mapItem(obj, deepClone) as T;
  }

  if (isPlainObject(obj) && obj.constructor === ObjectCls) {
    const clone = {} as T;
    forEach(objectKeys(obj), key => {
      clone[key as keyof T] = deepClone(obj[key as keyof T]);
    });
    return clone;
  }
  return obj;
}

