function sortByKey<
	T extends object,
	K extends StringKeys<T>
>( data: Array<T>, key: K ): Array<T> {
	return data.toSorted( ( a, b ) => ( a[ key ] as string ).localeCompare( b[ key ] as string ));
}

async function getAllFiles( dir: string, recursive = true ): Promise<string[]> {
	try {
		await access( dir );

		const files = await readdir( dir, {
			withFileTypes: true,
			recursive
		} );

		return files
			.filter( file => file.isFile() )
			.filter( file => !hasIgnoredExtension( file.name ) )
			.map( file => join( relative( process.cwd(), file.parentPath ), file.name ) );
	} catch {
		// Directory does not exist or is inaccessible
		return [];
	}
}

function updateMetafile(
  metafile: Metafile,
  basePath: string
): Metafile {
  const cwd = process.cwd();

  // Clone the original outputs object
  const outputs = Object.assign( {}, metafile.outputs );

  // Reset the outputs
  metafile.outputs = {};

  for ( const path of readdirSync( basePath, { encoding: 'utf8', recursive: true } ) ) {
    const absolutePath = resolve( basePath, path );
    const filename = basename( absolutePath );
    const originalOutput = outputs[ filename ];

    // If the output file name exists in the original outputs, add the updated relative path
    if ( originalOutput ) {
      metafile.outputs[ relative( cwd, absolutePath ) ] = originalOutput;
    }
  }

  return metafile;
}

function getFormat( name: string, module: Module ): ModuleFormat {
	if ( getTypeByName( name ) !== 'script' ) {
    return 'other';
  }

	return module.type === 'javascript/esm'
		? 'esm'
		: 'cjs';
