protected async getReportPath(): Promise<string> {
		const { filename, outputDir } = this.config;
		const regex = new RegExp( `^${ filename }_(\\d+)\\${ this.extension }$` );

		const versions = ( await getAllFiles( outputDir ) )
			.map( path => basename( path ).match( regex ) )
			.filter( match => match !== null )
			.map( match => parseInt( match[ 1 ], 10 ) );

		const maxVersion = Math.max( ...versions, -1 );
		const version = String( maxVersion + 1 );

		return format( {
			dir: this.config.outputDir,
			name: `${ filename }_${ version }`,
			ext: this.extension
		} );
	}

function updateDependencies( report: Report ): Array<Dependency> {
	const dependencies: Record<string, Array<string>> = {};

	report.resources
		.map( file => packageNameRegExp.exec( file.name ) )
		.filter( match => match !== null )
		.forEach( ( [ path, , name ] ) => {
			const paths = dependencies[ name ] ??= [];

			if ( !paths.includes( path ) ) {
				paths.push( path );
			}
		} );

	return Object
		.entries( dependencies )
		.map( ( [ name, paths ] ) => ( { name, paths } ) );
}

function updateOutput(
	report: Report,
	path: string,
	entrypoints: Array<string> | undefined,
): void {
	const type = getTypeByName( path );

	RESOURCE_TYPES_TO_ANALYZE.includes( type )
		? addAnalyzableType( report, path, entrypoints, type )
		: addNonAnalyzableType( report, path, type );
}

function addNonAnalyzableType( report: Report, path: string, type: FileType ): void {
	const content = readFileSync( path );
	const sizes = getSizes( content, report.config );

	report.addResource( {
		kind: 'asset',
		name: normalizePath( path ),
		type,
		...sizes
	} );
}

function addAnalyzableType( report: Report, path: string, entrypoints: Array<string> | undefined, type: FileType ): void {
	const assetName = normalizePath( path );
	const codeMap = getSource( path, report.config );

	if ( !codeMap ) {
		return addNonAnalyzableType( report, path, type );
	}

	const { code, map } = codeMap;
	const sizes = getSizes( code, report.config );
	const sourcesSizes = getBytesPerSource( code, map, sizes, report.config );

	report.addResource( {
		kind: 'asset',
		name: assetName,
		type,
		...sizes
	} );

	if ( report.config.sources ) {
		report.addSourceMap( assetName, normalizeSourceMap( map ) )
	}

	// Add `asset => entrypoint` connections
	entrypoints?.forEach( entry => report.addConnection( {
		kind: 'entrypoint',
		source: assetName,
		target: normalizePath( entry ),
		original: null
	} ) );

	// Add each source map source as a report "chunk"
	for ( const [ source, sizes ] of sourcesSizes ) {
		const name = normalizePath( source );
		const type = getTypeByName( source );
		const parent = parentMap[ source ] ? normalizePath( parentMap[ source ] ) : null;
		const existingSource = report.resources.find( resource => resource.name === name && resource.kind === 'filesystem' );

		// If source was not already added from "filesystem" then add it as a "sourcemap"
		if ( !existingSource ) {
			const index = map.sources.indexOf( source );
			const { uncompressed } = getSizes(
				map.sourcesContent?.[ index ] || '',
				{ gzip: false, brotli: false }
			);

			report.addResource( {
				kind: 'sourcemap',
				name,
				type,
				format: 'other',
				uncompressed,
				parent: parent || null
			} );
		}

		report.addResource( {
			kind: 'chunk',
			name,
			type,
			format: existingSource?.format || 'other',
			...sizes,
			parent: assetName
		} );

		if ( parent ) {
			// Add `bundle => sourcemap` connection
			report.addConnection( {
				kind: 'sourcemap',
				source: parent,
				target: name,
				original: null
			} );
		}
	}
}

function getSource( path: string, config: Config ): { code: string, map: DecodedSourceMap } | null {
	const codeMap = loadCodeAndMap( path, config.sourcesPathNormalizer );

	if ( !codeMap || !codeMap.map ) {
		return null;
	}

	return {
		code: codeMap.code,
		map: parseSourceMap( codeMap.map, config.deep )
	};
}

function getSizes(
	code: string | Buffer,
	config: Record<'gzip' | 'brotli', boolean>
): Sizes {
	return {
		uncompressed: Buffer.byteLength( code ),
		gzip: config.gzip ? gzipSync( code ).length : 0,
		brotli: config.brotli ? brotliCompressSync( code ).length : 0
	};
}

function factory( options?: Partial<Options> ): ReturnType<Factory> {
  const defaultOptions: Options = {
    include: /\.js$/,
    exclude: undefined,
  };

  const {
    include,
    exclude
  } = Object.assign({}, defaultOptions, options) as Options;

  return {
    name: 'unplugin-sourcemaps',
    enforce: 'pre',

    loadInclude( id: string ): boolean {
      return include.test(id) && !exclude?.test(id);
    },

    load( id: string ): TransformResult {
      return loadCodeAndMap( id ) as TransformResult;
    }
  };
}

function observeElementRect(
  /** The element whose rect to observe */
  elementToObserve: Measurable,
  /** The callback which will be called when the rect changes */
  callback: CallbackFn
) {
  const observedData = observedElements.get(elementToObserve);

  if (observedData === undefined) {
    // add the element to the map of observed elements with its first callback
    // because this is the first time this element is observed
    observedElements.set(elementToObserve, { rect: {} as DOMRect, callbacks: [callback] });

    if (observedElements.size === 1) {
      // start the internal loop once at least 1 element is observed
      rafId = requestAnimationFrame(runLoop);
    }
  } else {
    // only add a callback for this element as it's already observed
    observedData.callbacks.push(callback);
    callback(elementToObserve.getBoundingClientRect());
  }

  return () => {
    const observedData = observedElements.get(elementToObserve);
    if (observedData === undefined) return;

    // start by removing the callback
    const index = observedData.callbacks.indexOf(callback);
    if (index > -1) {
      observedData.callbacks.splice(index, 1);
    }

    if (observedData.callbacks.length === 0) {
      // stop observing this element because there are no
      // callbacks registered for it anymore
      observedElements.delete(elementToObserve);

      if (observedElements.size === 0) {
        // stop the internal loop once no elements are observed anymore
        cancelAnimationFrame(rafId);
      }
    }
  };
}

function runLoop() {
  const changedRectsData: Array<ObservedData> = [];

  // process all DOM reads first (getBoundingClientRect)
  observedElements.forEach((data, element) => {
    const newRect = element.getBoundingClientRect();

    // gather all the data for elements whose rects have changed
    if (!rectEquals(data.rect, newRect)) {
      data.rect = newRect;
      changedRectsData.push(data);
    }
  });

  // group DOM writes here after the DOM reads (getBoundingClientRect)
  // as DOM writes will most likely happen with the callbacks
  changedRectsData.forEach((data) => {
    data.callbacks.forEach((callback) => callback(data.rect));
  });

  rafId = requestAnimationFrame(runLoop);
}

function rectEquals(rect1: DOMRect, rect2: DOMRect) {
  return (
    rect1.width === rect2.width &&
    rect1.height === rect2.height &&
    rect1.top === rect2.top &&
    rect1.right === rect2.right &&
    rect1.bottom === rect2.bottom &&
    rect1.left === rect2.left
  );
}

setBefore(key: K, newKey: K, value: V) {
    const index = this.#keys.indexOf(key);
    if (index === -1) {
      return this;
    }
    return this.insert(index, newKey, value);
  }

setAfter(key: K, newKey: K, value: V) {
    const index = this.#keys.indexOf(key);
    if (index === -1) {
      return this;
    }
    return this.insert(index + 1, newKey, value);
  }

