calc = (...valuesAndOperators: (CalcVal | Operator)[]): string | number => {
  if (isWeb) {
    let res = 'calc('
    for (const cur of valuesAndOperators) {
      if (operators[cur as any]) {
        // spaces are significant
        res += ` ${cur} `
      } else {
        res += convertToVariableOrNumber(cur)
      }
    }
    return `${res})`
  }

  let res = 0
  let nextOp: any = null
  for (const cur of valuesAndOperators) {
    if (operators[cur as any]) {
      nextOp = operators[cur as any]
    } else {
      if (nextOp) {
